<?php require 'auth.php'; require_login(); $d=content(); if($_POST){ $items=[]; foreach(($_POST['name']??[]) as $i=>$name){ if(trim($name)!=='') $items[]=['name'=>$name,'text'=>$_POST['text'][$i]??'']; } $d['products']=$items; save_content($d); $msg='Products saved'; } ?>
<!doctype html><html><head><title>Edit Products</title><link rel="stylesheet" href="../assets/css/style.css"><style>.wrap{max-width:900px;margin:30px auto}input,textarea{width:100%;padding:10px;margin:6px 0;border:1px solid #ccc;border-radius:8px}.item{background:#fff;padding:15px;margin:12px 0;border-radius:10px}</style></head><body><div class="wrap"><h1>Products</h1><?php if(!empty($msg)) echo '<p style="color:green">'.$msg.'</p>'; ?><form method="post" id="f"><div id="items"><?php foreach($d['products'] as $p): ?><div class="item"><input name="name[]" value="<?=e($p['name'])?>" placeholder="Product name"><textarea name="text[]" placeholder="Description"><?=e($p['text'])?></textarea></div><?php endforeach; ?></div><button type="button" class="btn" onclick="addItem()">Add Product</button> <button class="btn">Save</button> <a href="index.php">Back</a></form></div><script>function addItem(){document.getElementById('items').insertAdjacentHTML('beforeend','<div class="item"><input name="name[]" placeholder="Product name"><textarea name="text[]" placeholder="Description"></textarea></div>')}</script></body></html>
